package main

import "fmt"

var todoList []string

func showMenu() {
	fmt.Println("\n=== YAPILACAKLAR LISTESI ===")
	fmt.Println("1. Gorev Ekle")
	fmt.Println("2. Gorevleri Listele")
	fmt.Println("3. Gorev Sil")
	fmt.Println("4. Cikis")
}

func addTask(task string) {
	todoList = append(todoList, task)
	fmt.Printf("Eklendi: '%s'\n", task)
}

func listTasks() {
	if len(todoList) == 0 {
		fmt.Println("Liste bos.")
		return
	}

	for i, task := range todoList {
		fmt.Printf("%d. %s\n", i+1, task)
	}
}

func removeTask(index int) {
	if index >= 0 && index < len(todoList) {
		fmt.Printf("Silindi: '%s'\n", todoList[index])
		todoList = append(todoList[:index], todoList[index+1:]...)
	} else {
		fmt.Println("Gecersiz numara.")
	}
}

func main() {
	showMenu()

	fmt.Println("\n> Secim: 1")
	addTask("Markete git")

	fmt.Println("\n> Secim: 1")
	addTask("Kod yaz")

	fmt.Println("\n> Secim: 1")
	addTask("Spor yap")

	fmt.Println("\n> Secim: 2")
	listTasks()

	fmt.Println("\n> Secim: 3 (1. gorevi sil)")
	removeTask(0)

	fmt.Println("\n> Secim: 2")
	listTasks()

	fmt.Println("\n> Secim: 4")
	fmt.Println("Programdan cikiliyor...")
}
